INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('c65ccfe0-1f9e-45c7-a4ca-c62a751cc96f', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1300', 'Applicability', 'This subpart applies to persons who manufacture, process, pack, or hold foods that appear on the Food Traceability List (FTL) designated by FDA under section 204(d)(2) of the FDA Food Safety Modernization Act. The FTL includes foods specifically listed and foods that contain listed foods as ingredients, provided the listed food remains in the same form in which it appears on the list. The list is published at www.fda.gov.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('e9fd535d-08ba-45cc-996d-9ec0e903a574', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1305', 'Exemptions', 'Exemptions from this subpart: (a) Small produce farms not covered under Part 112 or averaging ≤$25,000 annual sales (inflation-adjusted to 2020); shell egg producers with <3,000 laying hens; other RAC producers averaging ≤$25,000 annual sales. (b) Food produced and sold/donated directly to consumers by farm owner/operator. (c) Farm-packaged food with intact packaging and farm labeling (name, address, phone). (d) Produce receiving commercial processing that reduces pathogens; shell eggs receiving required treatment; foods subjected to kill steps; foods no longer on FTL; foods previously treated with kill steps. (e) Produce rarely consumed raw per §112.2(a)(1). (f) Raw bivalve molluscan shellfish under NSSP. (g) Foods under exclusive USDA jurisdiction (meat, poultry, egg products). (h) Commingled RACs with written agreements; FDA-registered entities must maintain source records for 2 years. (i) Small retail food establishments/restaurants with ≤$250,000 average annual sales (inflation-adjusted). (j) Retail establishments purchasing directly from farms; maintain farm source records for 180 days. (k) Ad hoc retail-to-retail purchases; purchaser maintains receipt documentation. (l) Farm-to-school programs; maintain farm records for 180 days. (m) Fishing vessels; FDA-registered entities maintain source records for 2 years. (n) Transporters of food. (o) Nonprofit food establishments. (p) Food manufactured/processed for personal consumption. (q) Food held for individual consumers (non-business, non-transactional). (r) Non-retail research/evaluation food with appropriate statement.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('61852b56-292d-4591-aaec-c624ac1e01cd', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1310', 'Definitions', 'Key definitions: Critical Tracking Event (CTE): supply chain event involving harvesting, cooling (before initial packing), initial packing of RACs (except fishing vessel food), first land-based receiving of fishing vessel food, shipping, receiving, or transformation. Key Data Element (KDE): information associated with CTEs requiring records under this subpart. Traceability Lot: batch or lot of food that has been initially packed, received by first land-based receiver, or transformed. Traceability Lot Code (TLC): alphanumeric descriptor uniquely identifying a traceability lot within records of the code source. Food Traceability List (FTL): designated list of foods requiring additional traceability records per FSMA section 204(d)(2). Kill Step: lethality processing significantly minimizing pathogens. Transformation: manufacturing/processing food or changing food (commingling, repacking, relabeling) or packaging/packing when output is an FTL food, excluding initial packing. Location Description: business name, phone number, physical address (or geographic coordinates), city, state, zip code (or comparable foreign information including country). Product Description: food description including product name (brand, commodity, variety), packaging size, packaging style; for seafood may include species/acceptable market name. Reference Document: business transaction document containing some or all KDEs for CTEs, including bills of lading, purchase orders, advance shipping notices, work orders, invoices, database records, batch logs, production logs, field tags, catch certificates, receipts. Shipping: arranging food transport from one location to another, excluding direct consumer sales/donations, including intracompany shipments between different addresses. Receiving: food received by non-consumer after transportation from another location, including intracompany shipments. Cooling: active temperature reduction using hydrocooling, icing, forced air cooling, vacuum cooling, or similar process. Harvesting: farm activities removing RACs from growing/raising locations. Initial Packing: first packing of RAC excluding fishing vessel food. First Land-Based Receiver: person taking possession of food from a fishing vessel on land for the first time.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('34a3523d-abbe-4e5a-8839-9faf4d40814a', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1315', 'Traceability Plan', 'Each person subject to this subpart must establish and maintain a traceability plan containing: (a)(1) Description of procedures used to maintain required records, including format and location. (a)(2) Description of procedures for identifying FTL foods manufactured, processed, packed, or held. (a)(3) Description of how traceability lot codes are assigned per §1.1320 (if applicable). (a)(4) Statement identifying a point of contact (name, job title, phone number) for questions regarding traceability plan and records. (a)(5)(i) For farms growing/raising food (other than eggs): map showing location and name of each field or growing area with geographic coordinates and other identifying information. (a)(5)(ii) For aquaculture: map showing location and name of each container (pond, pool, tank, cage) with geographic coordinates and identifying details. (b) Traceability plans must be updated to reflect current practices; previous versions retained for 2 years after updates.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('312831bf-7f99-4b2c-a401-4b8f008d60b3', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1320', 'Traceability Lot Code Assignment', '(a) You must assign a traceability lot code when you: (1) initially pack a raw agricultural commodity (other than fishing vessel food); (2) receive food as first land-based receiver from a fishing vessel; or (3) transform food. (b) You must NOT establish a new traceability lot code when you conduct other activities, such as shipping, for food already on the Food Traceability List. A traceability lot code must be an alphanumeric descriptor that uniquely identifies the traceability lot within your records.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('9d8ca564-c5c3-4f53-8607-cbf25327b589', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1325', 'Harvesting and Cooling Records', 'HARVESTING: (a)(1) If you harvest a RAC on the FTL (other than fishing vessel food), you must maintain records with the following KDEs linked to each traceability lot: (i) Location description for the immediate subsequent recipient (other than a transporter); (ii) Commodity and, if applicable, variety of the food; (iii) Quantity and unit of measure of the food (e.g., 75 bins, 200 pounds); (iv) Location description for the farm where the food was harvested; (v) For produce: the name of the field or other growing area from which the food was harvested (which may be set forth in the farm map in your traceability plan); for aquacultured food: the name of the container from which it was harvested; (vi) The date of harvesting; (vii) The reference document type and reference document number. (a)(2) You must provide (except reference documents) to the initial packer of the RAC or, if applicable, the person who cooled the RAC before initial packing. COOLING: (b)(1) If you cool a RAC on the FTL before it is initially packed (other than fishing vessel food), you must maintain records with KDEs: (i) Location description for the immediate subsequent recipient; (ii) Commodity and variety; (iii) Quantity and unit of measure; (iv) Location description for the cooling location; (v) Date of cooling; (vi) Location description for the farm where the food was harvested; (vii) Reference document type and number. (b)(2) You must provide the information (except reference documents) to the initial packer directly or through the supply chain.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('580cfe3c-6f53-49ce-9376-aed1bbfaed4a', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1330', 'Initial Packing Records', 'If you are performing initial packing of a RAC (other than fishing vessel food) on the FTL, you must maintain records linking the following KDEs to each traceability lot: (a) For most commodities: (1) Commodity and variety of food received; (2) Date received; (3) Quantity and unit of measure received; (4) Location description for farm where harvested; (5) Name of field/growing area (produce) or container (aquacultured food); (6) Business name and phone number of harvester; (7) Date of harvesting; (8) Location description for cooling (if applicable); (9) Date of cooling (if applicable); (10) Traceability lot code you assigned; (11) Product description for the packed food; (12) Quantity and unit of measure of the packed food; (13) Location description for where you initially packed the food (traceability lot code source), and if applicable, the traceability lot code source reference; (14) Date of initial packing; (15) Reference document type and number. (b) For sprouts: additional records including seed grower location and harvest date, seed conditioner/processor details, seed packinghouse information, seed supplier location and lot codes, seed description (type, growing specifications, packaging, antimicrobial treatment if applicable), seed receipt date. (c) When receiving from entities not subject to this subpart: simplified requirements excluding farm-level details.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('a78f745f-ff25-4e28-9510-054e7d85883c', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1335', 'First Land-Based Receiver Records', 'If you are the first land-based receiver of a food on the FTL obtained from a fishing vessel, you must maintain records for each traceability lot containing: (1) The traceability lot code you assigned; (2) The species and/or acceptable market name for unpackaged food, or the product description for packaged food; (3) Quantity and unit of measure; (4) The harvest date range and locations for the trip during which the food was caught, using National Marine Fisheries Service Ocean Geographic Code, FAO Major Fishing Area code, or equivalent standard; (5) The location description for where you received the food (first land-based receiver location), and if applicable, the traceability lot code source reference; (6) The date you received the food (landing date); (7) The reference document type and reference document number.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('c72ec3fe-3c0a-4f93-971a-c78052e20b41', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1340', 'Shipping Records', '(a) When you ship a food on the FTL (except as specified in paragraph (c)), you must maintain records linking the following KDEs to each traceability lot: (1) The traceability lot code for the food; (2) The quantity and unit of measure of the food (e.g., 6 cases, 25 returnable plastic containers, 100 tanks, 200 pounds); (3) The product description for the food; (4) The location description for the immediate subsequent recipient (other than a transporter) of the food; (5) The location description for the location from which you shipped the food; (6) The date you shipped the food; (7) The location description for the traceability lot code source, or the traceability lot code source reference; (8) The reference document type and reference document number. (b) You must provide information items (1) through (7) to the immediate subsequent recipient (other than a transporter) in electronic, paper, or other written form. (c) This section does not apply to the shipment of a RAC (other than food from a fishing vessel) that occurs before the initial packing of that RAC.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('9c823d59-2fcd-49be-805e-e06cc8f858dc', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1345', 'Receiving Records', '(a) Except as specified in paragraphs (b) and (c), when you receive a food on the FTL, you must maintain records linking the following KDEs to each traceability lot: (1) The traceability lot code for the food; (2) The quantity and unit of measure of the food (e.g., 6 cases, 25 returnable plastic containers, 100 tanks, 200 pounds); (3) The product description for the food; (4) The location description for the immediate previous source (other than a transporter) of the food; (5) The location description for where the food was received; (6) The date you received the food; (7) The location description for the traceability lot code source, or the traceability lot code source reference; (8) The reference document type and reference document number. (b) When receiving from sources not subject to this subpart, you must maintain similar records and assign a traceability lot code if one has not been assigned (except for retail establishments or restaurants). (c) Does not apply to receipt of RACs before initial packing or receipt by first land-based receiver of fishing vessel food.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('60c7b3ec-005d-4610-97f1-3bb3ea9ccb95', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1350', 'Transformation Records', 'When you transform a food on the FTL, for each new traceability lot you must maintain records containing: FOR EACH INPUT FOOD ON THE FTL USED: (1) The traceability lot code for the food; (2) The product description for the food; (3) The quantity and unit of measure of the food used from each lot. FOR THE TRANSFORMED OUTPUT: (4) The new traceability lot code for the food; (5) The location description for where you transformed the food (including traceability lot code source reference if applicable); (6) The date transformation was completed; (7) The product description for the new food; (8) The quantity and unit of measure of the new food; (9) The reference document type and reference document number. EXCEPTIONS: For RACs (excluding fishing vessel food) received unpacked for transformation, follow §1.1330(a) or (c) initial packing requirements. For sprouts, additionally follow §1.1330(b). Retail establishments and restaurants are exempt for food sold directly to consumers.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('3c459400-5de5-4eac-9809-c9edcd97de02', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1360', 'Modified Requirements and Exemptions', 'FDA may modify the requirements in this subpart that apply to a food or type of entity, or exempt a food or type of entity from the requirements, when FDA determines that application of the requirements is not necessary to protect public health. Modifications or exemptions may be initiated by petition or by FDA on its own initiative. Petitions must follow the procedures in 21 CFR §10.30 and include specific information about the food or entity type, the requirements at issue, and supporting evidence. FDA will publish proposed modifications/exemptions in the Federal Register with a 60-day comment period.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('5b5e47d6-e879-4180-844c-7ef149a22595', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1405', 'Waivers', 'FDA may waive one or more requirements of this subpart for an individual entity or a type of entity when FDA determines that: (1) The waiver will not significantly impair FDA ability to rapidly and effectively identify recipients of a food to prevent or mitigate a foodborne illness outbreak or address credible threats of serious adverse health consequences or death; and (2) The waiver is in the interest of public health, taking into account the entity''s stored data and procedures for providing information to FDA within 24 hours. Individual entity waivers may be requested directly. Type-of-entity waivers follow petition procedures. Waivers may be subject to conditions.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('e4f48ff4-21ae-4783-a272-c8ce0c569518', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1455', 'Record Maintenance and Availability', '(a) Records must be maintained as original paper or electronic records, or true copies, and must be legible and stored to prevent deterioration or loss. (b) Other entities may maintain records on your behalf, but you retain responsibility for retrieval and onsite provision within 24 hours. (c) Records must be available within 24 hours upon FDA request (or within reasonable agreed time), including coding systems and glossaries. (d) Offsite storage permitted if retrievable and providable onsite within 24 hours; electronic records satisfy this if accessible from onsite location. (e) In outbreak prevention or recall situations, information must be available within 24 hours via in-person or remote FDA request. (f) Records must generally be provided in electronic sortable spreadsheet format. Exemptions: farms with ≤$250,000 average annual sales, retail establishments with ≤$1M sales, and other entities with ≤$1M sales (all inflation-adjusted to 2020). Religious belief accommodations also permitted. (g) English translations required within reasonable time for non-English records. (h) Records must be retained for 2 years from creation/receipt date. (i) Traceability plan must document record format and location per §1.1315(a)(1). (j) Existing business records containing required information may be used without duplication.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('7d1e9b20-1fce-48d2-84d8-d79a10980126', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1460', 'Enforcement and Consequences', 'Failure to comply with the requirements of this subpart is a prohibited act under section 301(e) of the Federal Food, Drug, and Cosmetic Act (21 U.S.C. 331(e)). An article of food that is in violation of the requirements of this subpart is subject to refusal of admission into the United States under section 801(a) of the FD&C Act (21 U.S.C. 381(a)), except that food offered for import by a farm shall not be refused admission because of a violation of the requirements of this subpart by that farm.', '2026-01-20');
INSERT INTO regulations (id, tenant_id, source_name, citation, section, text, effective_date) VALUES ('616ef276-e14d-4f0a-b9b7-64a601ad7f16', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'FSMA Section 204 / 21 CFR Part 1 Subpart S', '21 CFR §1.1465', 'Food Traceability List Updates', 'FDA will update the Food Traceability List using a science-based risk-ranking model. Deletions from the list become effective immediately upon Federal Register publication. Additions to the list become effective 2 years after the Federal Register notice date, unless a different effective date is specified. Updates will consider factors including: (1) severity and length of illness; (2) domestic occurrence; (3) likelihood of contamination; (4) potential for growth/survival during manufacturing; (5) food consumption patterns; (6) point of origin and distribution in commerce; and (7) cost-effectiveness of additional recordkeeping.', '2026-01-20');
