INSERT INTO obligations (id, tenant_id, regulation_id, obligation_text, risk_category) VALUES ('26251ef1-0884-4f2b-b494-408ce7d91320', '5946c58f-ddf9-4db0-9baa-acb11c6fce91', 'e4f48ff4-21ae-4783-a272-c8ce0c569518', 'Retain all required records for 2 years from the date of creation or receipt', 'HIGH');
