-- V036 — FSMA 204 Regulatory Seed Data
-- Full 21 CFR Part 1 Subpart S: regulations, obligations, controls, and FTL
-- Generated from production data export
-- Tenant: 5946c58f-ddf9-4db0-9baa-acb11c6fce91 (demo)

BEGIN;

-- Create regulatory control-plane tables if the pre-baseline chain has not
-- already created them. Older Flyway deployments had these tables before
-- V036; a true Alembic fresh DB starts from zero and needs them here before
-- the seed data below can run.
CREATE TABLE IF NOT EXISTS regulations (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id UUID NOT NULL,
    source_name TEXT NOT NULL,
    citation TEXT NOT NULL,
    section TEXT,
    text TEXT NOT NULL,
    effective_date DATE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS obligations (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id UUID NOT NULL,
    regulation_id UUID REFERENCES regulations(id) ON DELETE CASCADE,
    obligation_text TEXT,
    title TEXT,
    description TEXT,
    risk_category TEXT,
    status TEXT DEFAULT 'active',
    due_date DATE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS controls (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id UUID NOT NULL,
    obligation_id UUID REFERENCES obligations(id) ON DELETE CASCADE,
    control_name TEXT,
    title TEXT,
    description TEXT,
    control_type TEXT,
    frequency TEXT,
    threshold_value TEXT,
    status TEXT DEFAULT 'active',
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Create food_traceability_list table if not exists
CREATE TABLE IF NOT EXISTS food_traceability_list (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    category TEXT NOT NULL,
    food_name TEXT NOT NULL,
    description TEXT,
    outbreak_risk TEXT NOT NULL CHECK (outbreak_risk IN ('HIGH', 'MODERATE')),
    applicable_ctes TEXT[] NOT NULL,
    required_kdes JSONB NOT NULL DEFAULT '{}',
    cfr_sections TEXT[] NOT NULL,
    examples TEXT[],
    exclusions TEXT[],
    effective_date DATE NOT NULL DEFAULT '2026-01-20',
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Fix overly restrictive CHECK constraints from earlier migrations
ALTER TABLE obligations DROP CONSTRAINT IF EXISTS obligations_risk_category_check;
ALTER TABLE obligations ADD CONSTRAINT obligations_risk_category_check CHECK (risk_category IN ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW', 'disparate_impact', 'disparate_treatment', 'documentation'));

ALTER TABLE controls DROP CONSTRAINT IF EXISTS controls_control_type_check;
ALTER TABLE controls ADD CONSTRAINT controls_control_type_check CHECK (control_type IN ('statistical_test', 'documentation', 'monitoring', 'preventive', 'detective', 'corrective'));

ALTER TABLE controls DROP CONSTRAINT IF EXISTS controls_frequency_check;
ALTER TABLE controls ADD CONSTRAINT controls_frequency_check CHECK (frequency IN ('real_time', 'monthly', 'quarterly', 'per_event', 'daily', 'weekly', 'semi-annual', 'annual', 'upon_change'));

-- Idempotent: clear existing seed data for demo tenant
DELETE FROM controls WHERE tenant_id = '5946c58f-ddf9-4db0-9baa-acb11c6fce91';
DELETE FROM obligations WHERE tenant_id = '5946c58f-ddf9-4db0-9baa-acb11c6fce91';
DELETE FROM regulations WHERE tenant_id = '5946c58f-ddf9-4db0-9baa-acb11c6fce91';
DELETE FROM food_traceability_list WHERE effective_date = '2026-01-20';

